// // This module implements a 2-bit binary counter with asynchronous reset and synchronous enable.
module counter_2bit (
  input clk,
  input reset,
  input enable,
  output reg [1:0] count
);

  always @(posedge clk) begin
    if (reset)
      count <= 2'b00;
    else if (enable)
      count <= count + 1;
  end

endmodule
